class Solution {
public:
    long long waysToBuyPensPencils(int total, int cost1, int cost2) {
        if (cost1 > total || cost2 > total) return 1;
        long long ways = 0;
        for (int i = 0; i <= total / cost1; i++) {
            ways += (total - i * cost1) / cost2 + 1;
        }
        return ways;
    }
};
```

